const _TXT="https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent",_IMG="https://generativelanguage.googleapis.com/v1beta/models/imagen-4.0-generate-001:predict";async function aiText(e){const t=await fetch(_TXT,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({contents:[{parts:[{text:e}]}],generationConfig:{temperature:.85,maxOutputTokens:4096}})});if(!t.ok){const e=await t.json().catch(()=>({}));throw new Error(e?.error?.message||"Gagal generate teks. Coba lagi.")}const a=await t.json();return a?.candidates?.[0]?.content?.parts?.[0]?.text||""}async function aiImage(e,t){t=Math.min(parseInt(t)||1,4);const a=await fetch(_IMG,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({instances:[{prompt:e}],parameters:{sampleCount:t}})});if(!a.ok){const e=await a.json().catch(()=>({}));throw new Error(e?.error?.message||"Gagal generate gambar. Coba lagi.")}const n=await a.json(),o=n?.predictions||[];if(!o.length)throw new Error("Tidak ada gambar yang dihasilkan.");return o.map(e=>{const t=e.mimeType||"image/png",a=atob(e.bytesBase64Encoded),n=new Uint8Array(a.length);for(let e=0;e<a.length;e++)n[e]=a.charCodeAt(e);return URL.createObjectURL(new Blob([n],{type:t}))})}